/**
 * All widget CSS, inlined into the iframe <style> tag.
 * Uses CSS custom properties defined by the theme engine.
 * All classes prefixed with mn- to avoid collisions.
 */
export declare const WIDGET_STYLES = "\n/* Reset */\n*, *::before, *::after {\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n}\n\n.mn-body {\n  font-family: var(--mn-font-family);\n  background-color: var(--mn-bg-color);\n  color: var(--mn-text-color);\n  line-height: 1.6;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\n.mn-container {\n  max-width: 640px;\n  margin: 0 auto;\n  padding: 24px 20px;\n}\n\n/* Header */\n.mn-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  flex-wrap: wrap;\n  margin-bottom: 20px;\n  padding-bottom: 16px;\n  border-bottom: 1px solid var(--mn-border-color);\n}\n\n.mn-logo {\n  height: 40px;\n  width: auto;\n  max-width: 120px;\n  object-fit: contain;\n}\n\n.mn-practice-name {\n  font-size: 18px;\n  font-weight: 600;\n  flex: 1;\n  min-width: 0;\n}\n\n/* Language toggle */\n.mn-lang-toggle {\n  display: flex;\n  gap: 4px;\n  margin-left: auto;\n}\n\n.mn-lang-btn {\n  background: transparent;\n  border: 1px solid var(--mn-border-color);\n  border-radius: 4px;\n  padding: 4px 10px;\n  font-size: 13px;\n  cursor: pointer;\n  color: var(--mn-text-secondary);\n  transition: all 0.15s ease;\n}\n\n.mn-lang-btn:hover {\n  border-color: var(--mn-brand-color);\n  color: var(--mn-brand-color);\n}\n\n.mn-lang-active {\n  background-color: var(--mn-brand-color);\n  border-color: var(--mn-brand-color);\n  color: #FFFFFF;\n}\n\n.mn-lang-active:hover {\n  color: #FFFFFF;\n}\n\n/* Meta info (date, doctor) */\n.mn-meta {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 16px;\n  margin-bottom: 20px;\n  font-size: 14px;\n  color: var(--mn-text-secondary);\n}\n\n.mn-meta-item strong {\n  color: var(--mn-text-color);\n}\n\n/* Summary */\n.mn-summary {\n  margin-bottom: 24px;\n}\n\n.mn-summary-heading {\n  font-size: 16px;\n  font-weight: 600;\n  margin-bottom: 12px;\n  color: var(--mn-brand-color);\n}\n\n.mn-summary-text {\n  font-size: 15px;\n  line-height: 1.7;\n  white-space: pre-wrap;\n}\n\n/* Medical terms */\n.mn-terms {\n  background-color: var(--mn-surface-color);\n  border: 1px solid var(--mn-border-color);\n  border-radius: 8px;\n  padding: 16px;\n  margin-bottom: 20px;\n}\n\n.mn-terms-heading {\n  font-size: 14px;\n  font-weight: 600;\n  margin-bottom: 12px;\n  color: var(--mn-brand-color);\n}\n\n.mn-terms-list {\n  display: grid;\n  gap: 8px;\n}\n\n.mn-term {\n  font-weight: 600;\n  font-size: 14px;\n  color: var(--mn-text-color);\n}\n\n.mn-term-explanation {\n  font-size: 13px;\n  color: var(--mn-text-secondary);\n  margin-left: 0;\n  margin-bottom: 8px;\n  padding-left: 12px;\n  border-left: 2px solid var(--mn-brand-color);\n}\n\n/* Disclaimer */\n.mn-disclaimer {\n  background-color: var(--mn-surface-color);\n  border: 1px solid var(--mn-border-color);\n  border-radius: 8px;\n  padding: 12px 16px;\n  font-size: 13px;\n  color: var(--mn-text-secondary);\n  margin-bottom: 20px;\n}\n\n.mn-disclaimer strong {\n  color: var(--mn-text-color);\n}\n\n/* Footer */\n.mn-footer {\n  text-align: center;\n  padding-top: 16px;\n  border-top: 1px solid var(--mn-border-color);\n}\n\n.mn-powered-by {\n  font-size: 12px;\n  color: var(--mn-text-secondary);\n}\n\n/* Loading state */\n.mn-loading {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  min-height: 200px;\n  gap: 16px;\n}\n\n.mn-spinner {\n  width: 32px;\n  height: 32px;\n  border: 3px solid var(--mn-border-color);\n  border-top-color: var(--mn-brand-color);\n  border-radius: 50%;\n  animation: mn-spin 0.8s linear infinite;\n}\n\n@keyframes mn-spin {\n  to { transform: rotate(360deg); }\n}\n\n.mn-loading-text {\n  font-size: 14px;\n  color: var(--mn-text-secondary);\n}\n\n/* Error state */\n.mn-error {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  min-height: 200px;\n  gap: 12px;\n  text-align: center;\n}\n\n.mn-error-icon {\n  font-size: 36px;\n  color: var(--mn-text-secondary);\n}\n\n.mn-error-text {\n  font-size: 14px;\n  color: var(--mn-text-secondary);\n  max-width: 400px;\n}\n\n/* Token form */\n.mn-token-form .mn-form {\n  max-width: 360px;\n  margin: 24px auto;\n}\n\n.mn-label {\n  display: block;\n  font-size: 14px;\n  font-weight: 600;\n  margin-bottom: 8px;\n}\n\n.mn-input {\n  display: block;\n  width: 100%;\n  padding: 10px 12px;\n  border: 1px solid var(--mn-border-color);\n  border-radius: 6px;\n  font-size: 15px;\n  background-color: var(--mn-bg-color);\n  color: var(--mn-text-color);\n  margin-bottom: 12px;\n  outline: none;\n  transition: border-color 0.15s ease;\n}\n\n.mn-input:focus {\n  border-color: var(--mn-brand-color);\n  box-shadow: 0 0 0 2px color-mix(in srgb, var(--mn-brand-color) 20%, transparent);\n}\n\n.mn-submit-btn {\n  display: block;\n  width: 100%;\n  padding: 10px 16px;\n  background-color: var(--mn-brand-color);\n  color: #FFFFFF;\n  border: none;\n  border-radius: 6px;\n  font-size: 15px;\n  font-weight: 600;\n  cursor: pointer;\n  transition: opacity 0.15s ease;\n}\n\n.mn-submit-btn:hover {\n  opacity: 0.9;\n}\n\n/* Responsive */\n@media (max-width: 480px) {\n  .mn-container {\n    padding: 16px 12px;\n  }\n\n  .mn-header {\n    flex-direction: column;\n    align-items: flex-start;\n  }\n\n  .mn-lang-toggle {\n    margin-left: 0;\n  }\n\n  .mn-meta {\n    flex-direction: column;\n    gap: 4px;\n  }\n}\n";
